```javascript
function makeItQuack(obj) {
  // We don't care what 'obj' is. We only care if it has .quack()
  if (typeof obj.quack === 'function') {
    obj.quack();
  }
}

// Object A: A real Duck
const duck = {
  name: "Donald",
  quack: () => console.log("Quack!")
};

// Object B: A Robot
const robot = {
  name: "R2D2",
  quack: () => console.log("Beep Boop!")
};

**Example (TypeScript):**
```typescript
interface Duck {
  name: string;
  quack: () => void;
}

function makeItQuack(obj: Duck) {
  obj.quack();
}

const duck = {
  name: "Donald",
  quack: () => console.log("Quack!")
};

const robot = {
  name: "R2D2",
  quack: () => console.log("Beep Boop!")
};

const string = "I am a string";
makeItQuack(string); // ❌ ERROR: Type 'string' is not assignable to type 'Duck'.
```

```typescript
interface Duck {
  quack(): void;
}

interface Robot {
  quack(): void;
}

function makeItQuack(obj: Duck) {
  obj.quack();
}

const robot: Robot = {
  quack: () => console.log("Beep")
};

// TypeScript allows this!
// Even though 'robot' is not a 'Duck', it has the same structure.
makeItQuack(robot); 
```

